// SceneAccessServiceHandler is an implementation of the holomush.sceneaccess.v1.SceneAccessService
// service.
type SceneAccessServiceHandler interface {
	// ListScenesForViewer returns the public scene board filtered by the
	// verified player's character-scope and player-scope content-warning
	// blocks. The facade resolves the acting character from the player
	// session (INV-SCENE-63) and forwards a ListScenes call to the plugin
	// SceneService with the server-verified character_id.
	ListScenesForViewer(context.Context, *connect.Request[v1.ListScenesForViewerRequest]) (*connect.Response[v1.ListScenesForViewerResponse], error)
	// GetSceneForViewer loads one scene's metadata for the verified player's
	// owned character. The facade resolves the acting character from the
	// player session (INV-SCENE-63) and forwards a GetScene call to the
	// plugin SceneService with the server-verified character_id.
	GetSceneForViewer(context.Context, *connect.Request[v1.GetSceneForViewerRequest]) (*connect.Response[v1.GetSceneForViewerResponse], error)
	// ListMyScenes returns every non-archived scene the verified player's
	// owned character participates in (any role), with activity metadata
	// for workspace badge rendering. The facade resolves the acting character
	// from the player session (INV-SCENE-63) and forwards a
	// ListCharacterScenes call to the plugin SceneService with the
	// server-verified character_id.
	ListMyScenes(context.Context, *connect.Request[v1.ListMyScenesRequest]) (*connect.Response[v1.ListMyScenesResponse], error)
	// WatchScene auto-joins the verified player's owned character into an
	// OPEN, active scene as a role=observer participant and registers a
	// FocusMembership on the character's existing game session (which must
	// already exist — use SelectCharacter first). The facade resolves the
	// acting character from the player session (INV-SCENE-63), looks up the
	// character's game session via FindByCharacter, and forwards a
	// WatchScene call to the plugin SceneService with the server-verified
	// character_id and session_id. Returns FailedPrecondition when no game
	// session exists for the character (select the character first).
	WatchScene(context.Context, *connect.Request[v1.WatchSceneRequest]) (*connect.Response[v1.WatchSceneResponse], error)
	// CreateScene creates a new scene owned by the verified player's owned
	// character and returns its full metadata. The facade resolves the acting
	// character from the player session (INV-SCENE-63) and rejects guests
	// (INV-SCENE-64), then forwards a CreateScene call to the plugin SceneService
	// with the server-verified character_id. Unlike WatchScene it requires no
	// existing game session — creation does not touch focus.
	CreateScene(context.Context, *connect.Request[v1.CreateSceneRequest]) (*connect.Response[v1.CreateSceneResponse], error)
	// EndScene transitions the verified owner's scene to `ended`. The facade
	// resolves the acting character from the player session (INV-SCENE-63),
	// rejects guests (INV-SCENE-64), then forwards to SceneService.EndScene,
	// which self-enforces the ABAC `end` policy (INV-SCENE-65). Returns the
	// post-transition scene row.
	EndScene(context.Context, *connect.Request[v1.EndSceneRequest]) (*connect.Response[v1.EndSceneResponse], error)
	// PauseScene transitions the verified owner's active scene to `paused`.
	// Same identity/guest gating as EndScene; forwards to SceneService.PauseScene
	// which self-enforces the ABAC `pause` policy (INV-SCENE-65).
	PauseScene(context.Context, *connect.Request[v1.PauseSceneRequest]) (*connect.Response[v1.PauseSceneResponse], error)
	// ResumeScene transitions the verified participant's paused scene to `active`.
	// Same identity/guest gating as EndScene; forwards to SceneService.ResumeScene
	// which self-enforces the ABAC `resume` policy (participant-wide, INV-SCENE-65).
	ResumeScene(context.Context, *connect.Request[v1.ResumeSceneRequest]) (*connect.Response[v1.ResumeSceneResponse], error)
	// UpdateScene applies an owner's partial edit to mutable scene metadata. The
	// facade resolves the acting character from the player session (INV-SCENE-63),
	// rejects guests (INV-SCENE-64), then forwards to SceneService.UpdateScene,
	// which self-enforces the ABAC `update` policy (owner-only, INV-SCENE-65) and
	// applies only the fields named in update_mask (AIP-134). Returns the
	// post-update scene row.
	UpdateScene(context.Context, *connect.Request[v1.UpdateSceneRequest]) (*connect.Response[v1.UpdateSceneResponse], error)
	// InviteToScene resolves the verified acting character from the player session
	// (INV-SCENE-63), rejects guests (INV-SCENE-64), then forwards to
	// SceneService.InviteToScene, which self-enforces the ABAC `invite` policy
	// (participant-wide per the relaxation, INV-SCENE-65).
	InviteToScene(context.Context, *connect.Request[v1.InviteToSceneRequest]) (*connect.Response[v1.InviteToSceneResponse], error)
	// KickFromScene forwards to SceneService.KickFromScene, which self-enforces the
	// owner-only `kick` policy (INV-SCENE-65). Same identity/guest gating as above.
	KickFromScene(context.Context, *connect.Request[v1.KickFromSceneRequest]) (*connect.Response[v1.KickFromSceneResponse], error)
	// TransferOwnership forwards to SceneService.TransferOwnership, which
	// self-enforces the owner-only `transfer-ownership` policy (INV-SCENE-65).
	TransferOwnership(context.Context, *connect.Request[v1.TransferOwnershipRequest]) (*connect.Response[v1.TransferOwnershipResponse], error)
	// LeaveScene forwards to SceneService.LeaveScene, which self-enforces the
	// participant `leave` policy (INV-SCENE-65). The owner cannot leave.
	LeaveScene(context.Context, *connect.Request[v1.LeaveSceneRequest]) (*connect.Response[v1.LeaveSceneResponse], error)
	// StartScenePublish starts a publication vote on an ended scene. Participant-
	// gated inside the plugin (INV-SCENE-33: no ABAC engine on this path); the
	// facade resolves session/character and dispatches without an engine call.
	StartScenePublish(context.Context, *connect.Request[v1.StartScenePublishRequest]) (*connect.Response[v1.StartScenePublishResponse], error)
	// CastPublishSceneVote casts or changes the caller's Yes/No vote on the
	// active attempt. Frozen-roster participant gate enforced in the plugin store.
	CastPublishSceneVote(context.Context, *connect.Request[v1.CastPublishSceneVoteRequest]) (*connect.Response[v1.CastPublishSceneVoteResponse], error)
	// WithdrawScenePublish aborts the active attempt (scene owner only; gate in
	// the plugin handler).
	WithdrawScenePublish(context.Context, *connect.Request[v1.WithdrawScenePublishRequest]) (*connect.Response[v1.WithdrawScenePublishResponse], error)
	// GetPublishedScene reads the active attempt's status + vote tally for a
	// participant cold-start snapshot. Participant-gated (INV-SCENE-60); the
	// facade passes the plugin's status; the response is trimmed (no frozen
	// content — that is GetPublicSceneArchive's job).
	GetPublishedScene(context.Context, *connect.Request[v1.GetPublishedSceneRequest]) (*connect.Response[v1.GetPublishedSceneResponse], error)
	// ExportScene renders the verified player's owned character's scene IC
	// log to a downloadable document. The facade resolves the acting character
	// from the player session (INV-SCENE-63) and forwards an ExportSceneLog
	// call to the plugin SceneService with the server-verified character_id.
	ExportScene(context.Context, *connect.Request[v1.ExportSceneRequest]) (*connect.Response[v1.ExportSceneResponse], error)
	// SetSceneFocus sets the per-connection focus for a web portal connection
	// belonging to the verified player's character. The facade verifies that
	// the connection belongs to a session owned by one of the player's
	// characters (INV-SCENE-63) before calling the focus coordinator's
	// SetConnectionFocus.
	SetSceneFocus(context.Context, *connect.Request[v1.SetSceneFocusRequest]) (*connect.Response[v1.SetSceneFocusResponse], error)
	// ListPublishedScenes pages through publicly visible PUBLISHED scene
	// archives, newest first, with optional tag filtering. No character
	// identity is required for the underlying query, but the player session
	// token + guest gate are still enforced (INV-SCENE-64). The facade
	// forwards a ListPublishedScenes call to the plugin SceneService.
	ListPublishedScenes(context.Context, *connect.Request[v1.ListPublishedScenesRequest]) (*connect.Response[v1.ListPublishedScenesResponse], error)
	// GetPublicSceneArchive reads a published scene archive without participant
	// authentication. The only gate on the plugin call is status==PUBLISHED
	// (INV-SCENE-35); the facade adds the player-session token check and
	// guest-player denial (INV-SCENE-64). Forwards a GetPublicSceneArchive
	// call to the plugin SceneService.
	GetPublicSceneArchive(context.Context, *connect.Request[v1.GetPublicSceneArchiveRequest]) (*connect.Response[v1.GetPublicSceneArchiveResponse], error)
	// DownloadPublicSceneArchive returns a PUBLISHED scene archive rendered in
	// the requested format. Same status-gate and opacity contract as
	// GetPublicSceneArchive (INV-SCENE-35); the facade enforces the
	// player-session token check and guest-player denial (INV-SCENE-64).
	// Forwards a DownloadPublicSceneArchive call to the plugin SceneService.
	DownloadPublicSceneArchive(context.Context, *connect.Request[v1.DownloadPublicSceneArchiveRequest]) (*connect.Response[v1.DownloadPublicSceneArchiveResponse], error)
}

